import random
import math
import time
ciphertext = ""

RESTARTS = 200
ITERATIONS = 3000

alphabet = "ABCDEFGHIKLMNOPQRSTUVWXYZ"

quadgrams = {}
with open("quadgram.txt") as f: 
    print("Loading quadgrams...")
    total = 0
    for line in f:
        q, count = line.split()
        quadgrams[q] = int(count)
        total += int(count)

for q in quadgrams:
    quadgrams[q] = math.log10(quadgrams[q] / total)

FLOOR = math.log10(0.01 / total)

def score(text):
    s = 0
    for i in range(len(text) - 3):
        quad = text[i:i+4]
        if quad in quadgrams:
            s += quadgrams[quad]
        else:
            s += FLOOR
    return s

def get_position(key, letter):
    index = key.index(letter)
    return index // 5, index % 5

def decrypt_pair(a, b, key):
    r1, c1 = get_position(key, a)
    r2, c2 = get_position(key, b)

    if r1 == r2:
        c1 = (c1 - 1) % 5
        c2 = (c2 - 1) % 5
    elif c1 == c2:
        r1 = (r1 - 1) % 5
        r2 = (r2 - 1) % 5
    else:
        c1, c2 = c2, c1

    return key[r1*5 + c1] + key[r2*5 + c2]

def decrypt(cipher, key):
    plaintext = ""
    for i in range(0, len(cipher), 2):
        plaintext += decrypt_pair(cipher[i], cipher[i+1], key)
    return plaintext

# hill climb
def random_key():
    key = list(alphabet)
    random.shuffle(key)
    return key

def swap(key):
    a = random.randint(0, 24)
    b = random.randint(0, 24)
    new_key = key[:]
    new_key[a], new_key[b] = new_key[b], new_key[a]
    return new_key

def clean_text(text):
    text = text.upper()
    text = text.replace("J", "I") 
    return "".join([c for c in text if c in alphabet])

def hill_climb(cipher):
    best_global_score = -1e100
    best_global_plain = ""
    best_global_key = None

    for restart in range(RESTARTS):

        key = random_key()
        plain = decrypt(cipher, key)
        best_local_score = score(plain)

        for _ in range(ITERATIONS):
            candidate_key = swap(key)
            candidate_plain = decrypt(cipher, candidate_key)
            candidate_score = score(candidate_plain)

            if candidate_score > best_local_score:
                key = candidate_key
                best_local_score = candidate_score

        if best_local_score > best_global_score:
            best_global_score = best_local_score
            best_global_plain = decrypt(cipher, key)
            best_global_key = key
            print("\n=== NEW BEST ===")
            print("Score:", best_global_score)
            print("Key:", "".join(best_global_key))
            print("Plaintext:", best_global_plain[:300])

    return best_global_key, best_global_plain

if __name__ == "__main__":
    cipher = clean_text(ciphertext)
    start = time.time()
    key, plaintext = hill_climb(cipher)
    end = time.time()

    print("\n==============================")
    print("FINAL RESULT")
    print("Key:", "".join(key))
    print("Time:", round(end-start, 2), "seconds")
    print("\nPLAINTEXT:\n") #hasil akhir
    print(plaintext)